    // 3. Check allocation without monitoring
    snapshot.smallAllowedWithoutMonitoring = StackMonitor::canAllocate(16); // Small size
    snapshot.largeAllowedWithoutMonitoring = StackMonitor::canAllocate(SBOConfig::MAX_SBO_SIZE + 1);
